"use client"

import * as React from "react"
import {
  ColumnDef,
  flexRender,
  getCoreRowModel,
  getFilteredRowModel,
  getPaginationRowModel,
  getSortedRowModel,
  SortingState,
  useReactTable,
  VisibilityState,
  TableOptions,
} from "@tanstack/react-table"
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table"

export interface DataTableProps<TData, TValue> {
  columns: ColumnDef<TData, TValue>[]
  data: TData[]
  /**
   * Key used to persist column visibility to localStorage.
   * Provide a unique key per table instance.
   */
  storageKey?: string
  /**
   * Enable manual server-side sorting. When true the table will not sort data
   * internally — the consumer is responsible for re-fetching sorted data.
   * Defaults to true.
   */
  manualSorting?: boolean
  /**
   * Initial sorting state, useful when reading sort params from URL on mount.
   */
  initialSorting?: SortingState
  /**
   * Called whenever the sort state changes (only relevant when manualSorting is true).
   */
  onSortingChange?: (sorting: SortingState) => void
  /**
   * Message shown when there are no rows. Defaults to "No results."
   */
  emptyMessage?: string
  /**
   * Fixed page size for the internal pagination model.
   * When using server-side pagination, pass the slice of data for the current
   * page and set this to data.length or a large number. Defaults to 20.
   */
  pageSize?: number
  className?: string
}

export function DataTable<TData, TValue>({
  columns,
  data,
  storageKey,
  manualSorting = true,
  initialSorting = [],
  onSortingChange,
  emptyMessage = "No results.",
  pageSize = 20,
  className,
}: DataTableProps<TData, TValue>) {
  const [sorting, setSorting] = React.useState<SortingState>(initialSorting)

  // Column visibility with optional localStorage persistence
  const [columnVisibility, setColumnVisibility] = React.useState<VisibilityState>(() => {
    if (!storageKey || typeof window === "undefined") return {}
    try {
      const stored = window.localStorage.getItem(storageKey)
      return stored ? (JSON.parse(stored) as VisibilityState) : {}
    } catch {
      return {}
    }
  })

  React.useEffect(() => {
    if (!storageKey || typeof window === "undefined") return
    try {
      window.localStorage.setItem(storageKey, JSON.stringify(columnVisibility))
    } catch {
      // Silently ignore storage errors
    }
  }, [columnVisibility, storageKey])

  const handleSortingChange = React.useCallback(
    (updater: React.SetStateAction<SortingState>) => {
      setSorting((prev) => {
        const next = typeof updater === "function" ? updater(prev) : updater
        onSortingChange?.(next)
        return next
      })
    },
    [onSortingChange]
  )

  const tableConfig = {
    data: data ?? [],
    columns,
    onSortingChange: handleSortingChange,
    getCoreRowModel: getCoreRowModel(),
    getPaginationRowModel: getPaginationRowModel(),
    getSortedRowModel: getSortedRowModel(),
    getFilteredRowModel: getFilteredRowModel(),
    onColumnVisibilityChange: setColumnVisibility,
    manualSorting,
    state: {
      sorting,
      columnVisibility,
      pagination: {
        pageIndex: 0,
        pageSize,
      },
    },
  } satisfies Partial<TableOptions<TData>>

  const table = useReactTable(tableConfig as TableOptions<TData>)

  return (
    <Table className={`whitespace-nowrap${className ? ` ${className}` : ""}`}>
      <TableHeader className="sticky top-0 bg-muted z-10">
        {table.getHeaderGroups().map((headerGroup) => (
          <TableRow key={headerGroup.id}>
            {headerGroup.headers.map((header) => (
              <TableHead key={header.id} className="text-xs font-bold">
                {header.isPlaceholder
                  ? null
                  : flexRender(header.column.columnDef.header, header.getContext())}
              </TableHead>
            ))}
          </TableRow>
        ))}
      </TableHeader>
      <TableBody>
        {table.getRowModel().rows?.length ? (
          table.getRowModel().rows.map((row) => (
            <TableRow key={row.id} data-state={row.getIsSelected() && "selected"}>
              {row.getVisibleCells().map((cell) => (
                <TableCell key={cell.id}>
                  {flexRender(cell.column.columnDef.cell, cell.getContext())}
                </TableCell>
              ))}
            </TableRow>
          ))
        ) : (
          <TableRow>
            <TableCell colSpan={columns.length} className="h-24 text-center">
              {emptyMessage}
            </TableCell>
          </TableRow>
        )}
      </TableBody>
    </Table>
  )
}

"use client"

import * as React from "react"
import {
  Pagination,
  PaginationContent,
  PaginationEllipsis,
  PaginationItem,
  PaginationLink,
} from "@/components/ui/pagination"
import { ChevronLeft, ChevronRight } from "lucide-react"

export interface DataTablePaginationProps {
  /** Total number of records across all pages. */
  total: number
  /** Currently active page (1-indexed). */
  currentPage: number
  /** Number of records per page. */
  pageSize: number
  /**
   * Called when the user navigates to a new page.
   * The consumer is responsible for updating the URL or state.
   */
  onPageChange: (page: number) => void
  /** Label shown before the total count. Defaults to showing just the count. */
  resultsLabel?: string
  className?: string
}

function getPageNumbers(params: {
  currentPage: number
  pageSize: number
  total: number
}): (number | "...")[] {
  const { currentPage, pageSize, total } = params
  const totalPages = Math.ceil(total / pageSize)
  if (totalPages <= 7) {
    return Array.from({ length: totalPages }, (_, i) => i + 1)
  }
  const pages: (number | "...")[] = [1]
  if (currentPage > 3) pages.push("...")
  const start = Math.max(2, currentPage - 1)
  const end = Math.min(totalPages - 1, currentPage + 1)
  for (let i = start; i <= end; i++) pages.push(i)
  if (currentPage < totalPages - 2) pages.push("...")
  pages.push(totalPages)
  return pages
}

export function DataTablePagination({
  total,
  currentPage,
  pageSize,
  onPageChange,
  resultsLabel,
  className,
}: DataTablePaginationProps) {
  const isFirstPage = currentPage <= 1
  const isLastPage = currentPage * pageSize >= total
  const pageNumbers = getPageNumbers({ currentPage, pageSize, total })

  return (
    <div
      className={`flex flex-col md:flex-row items-center justify-between gap-2${className ? ` ${className}` : ""}`}
    >
      {/* Results count */}
      <div className="hidden md:block text-sm text-muted-foreground">
        {resultsLabel ? `${total} ${resultsLabel}` : total}
      </div>

      <Pagination className="w-auto">
        <PaginationContent>
          {/* Previous */}
          <PaginationItem>
            <PaginationLink
              size={undefined}
              onClick={!isFirstPage ? () => onPageChange(currentPage - 1) : undefined}
              className={
                isFirstPage ? "text-muted-foreground pointer-events-none" : "cursor-pointer"
              }
              aria-disabled={isFirstPage}
            >
              <ChevronLeft size={15} />
            </PaginationLink>
          </PaginationItem>

          {/* Page numbers */}
          {pageNumbers.length ? (
            pageNumbers.map((pageNumber, i) =>
              pageNumber === "..." ? (
                <PaginationItem key={`ellipsis-${i}`}>
                  <PaginationEllipsis />
                </PaginationItem>
              ) : (
                <PaginationItem key={pageNumber}>
                  <PaginationLink
                    size={undefined}
                    isActive={pageNumber === currentPage}
                    onClick={
                      pageNumber !== currentPage
                        ? () => onPageChange(pageNumber as number)
                        : undefined
                    }
                    className={pageNumber !== currentPage ? "cursor-pointer" : undefined}
                  >
                    {pageNumber}
                  </PaginationLink>
                </PaginationItem>
              )
            )
          ) : (
            <PaginationItem>
              <PaginationLink size={undefined} isActive>
                1
              </PaginationLink>
            </PaginationItem>
          )}

          {/* Next */}
          <PaginationItem>
            <PaginationLink
              size={undefined}
              onClick={!isLastPage ? () => onPageChange(currentPage + 1) : undefined}
              className={
                isLastPage ? "text-muted-foreground pointer-events-none" : "cursor-pointer"
              }
              aria-disabled={isLastPage}
            >
              <ChevronRight size={15} />
            </PaginationLink>
          </PaginationItem>
        </PaginationContent>
      </Pagination>
    </div>
  )
}

"use client"

import { MixerHorizontalIcon } from "@radix-ui/react-icons"
import { Table } from "@tanstack/react-table"
import { Button } from "@/components/ui/button"
import {
  DropdownMenu,
  DropdownMenuCheckboxItem,
  DropdownMenuContent,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu"

export interface DataTableViewOptionsProps<TData> {
  table: Table<TData>
  /** Label shown at the top of the dropdown. Defaults to "Columns". */
  label?: string
  /**
   * Optional function to resolve a human-readable name for a column id.
   * Defaults to displaying the raw column id.
   */
  getColumnLabel?: (columnId: string) => string
}

export function DataTableViewOptions<TData>({
  table,
  label = "Columns",
  getColumnLabel,
}: DataTableViewOptionsProps<TData>) {
  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <Button variant="outline" className="h-8 w-8 p-0" aria-label={label}>
          <MixerHorizontalIcon className="h-3.5 w-3.5" />
        </Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent align="end" className="w-[240px]">
        <DropdownMenuLabel>{label}</DropdownMenuLabel>
        <DropdownMenuSeparator />
        {table
          .getAllColumns()
          .filter(
            (column) =>
              typeof column.accessorFn !== "undefined" && column.getCanHide()
          )
          .map((column) => {
            const displayLabel = getColumnLabel ? getColumnLabel(column.id) : column.id
            return (
              <DropdownMenuCheckboxItem
                key={column.id}
                className="capitalize"
                checked={column.getIsVisible()}
                onCheckedChange={(value: boolean) => column.toggleVisibility(!!value)}
              >
                {displayLabel}
              </DropdownMenuCheckboxItem>
            )
          })}
      </DropdownMenuContent>
    </DropdownMenu>
  )
}
